package com.anvritai.abhay.config;
import jakarta.servlet.*;import jakarta.servlet.http.*;import java.io.IOException;import java.time.*;import java.util.concurrent.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.core.Ordered;import org.springframework.core.annotation.Order;import org.springframework.http.MediaType;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;
@Component @Order(Ordered.HIGHEST_PRECEDENCE+1) public class ApiProtectionFilter extends OncePerRequestFilter{
 private record Counter(long minute,int count){} private final ConcurrentMap<String,Counter> limits=new ConcurrentHashMap<>();private final ConcurrentMap<String,Instant> replayKeys=new ConcurrentHashMap<>();@Value("${abhay.security.rate-limit-enabled:true}") private boolean enabled;
 @Override protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{if(!enabled){chain.doFilter(req,res);return;}String path=req.getRequestURI();int max=path.startsWith("/api/auth/")?10:path.contains("/documents")?20:path.contains("/automation")?60:120;if(exceeded(req.getRemoteAddr()+":"+path,max)){error(res,429,"RATE_LIMITED","Too many requests. Please retry shortly.");return;}if(mutating(req.getMethod())){String key=req.getHeader("Idempotency-Key");if(key!=null&&!key.isBlank()){if(key.length()>100||!key.matches("[A-Za-z0-9._:-]+")){error(res,400,"INVALID_IDEMPOTENCY_KEY","The idempotency key is invalid.");return;}Instant old=replayKeys.putIfAbsent(req.getRemoteAddr()+":"+path+":"+key,Instant.now());if(old!=null&&old.isAfter(Instant.now().minusSeconds(600))){error(res,409,"REPLAY_REJECTED","This request was already submitted.");return;}}}chain.doFilter(req,res);cleanup();}
 private boolean exceeded(String key,int max){long minute=System.currentTimeMillis()/60000;Counter c=limits.compute(key,(k,v)->v==null||v.minute()!=minute?new Counter(minute,1):new Counter(minute,v.count()+1));return c.count()>max;}private boolean mutating(String m){return m.equals("POST")||m.equals("PATCH")||m.equals("PUT")||m.equals("DELETE");}private void cleanup(){long minute=System.currentTimeMillis()/60000;if(limits.size()>10000)limits.entrySet().removeIf(e->e.getValue().minute()<minute);if(replayKeys.size()>10000)replayKeys.entrySet().removeIf(e->e.getValue().isBefore(Instant.now().minusSeconds(600)));}
 private void error(HttpServletResponse r,int status,String code,String message)throws IOException{r.setStatus(status);r.setContentType(MediaType.APPLICATION_JSON_VALUE);r.getWriter().write("{\"code\":\""+code+"\",\"message\":\""+message+"\"}");}
}
